findings.suggestion:
Wrap each client.tools() call in try/catch and either skip failed servers with a warning or collect errors alongside results:

```typescript
async aggregateTools(): Promise<{ tools: Record<string, unknown>; errors: Array<{ serverId: string; error: string }> }> {
  const allTools: Record<string, unknown> = {}
  const errors: Array<{ serverId: string; error: string }> = []

  for (const [serverId, client] of this.clients) {
    try {
      const tools = await client.tools()
      for (const [toolName, toolDef] of Object.entries(tools)) {
        allTools[toolName in allTools ? `${serverId}__${toolName}` : toolName] = toolDef
      }
    } catch (err) {
      errors.push({ serverId, error: err instanceof Error ? err.message : String(err) })
    }
  }

  return { tools: allTools, errors }
}
```

